// ============================================
// ENERGY BAR CHART - Helpers Configuration
// ============================================

const dataFrame = context.dataFrame;

// Extrai valores de energia
let maxValue = 100;
let dataLength = 0;

if (dataFrame && dataFrame.fields) {
  const energyField = dataFrame.fields.find(f => f.name === 'energy_mwh');
  if (energyField && energyField.values) {
    const values = energyField.values.filter(v => v !== null && v !== undefined);
    dataLength = values.length;
    if (values.length > 0) {
      maxValue = Math.max(...values);
    }
  }
}

// Calcula escala do eixo Y (arredonda para múltiplo de 100)
const roundTo = 100;
const maxScale = Math.max(Math.ceil(maxValue / roundTo) * roundTo, roundTo);
const ySteps = Math.min(maxScale / roundTo, 5); // máximo 5 divisões
const yInterval = maxScale / ySteps;

// Gera array de labels do eixo Y (de cima para baixo)
const yLabels = [];
for (let i = maxScale; i >= 0; i -= yInterval) {
  yLabels.push(Math.round(i));
}
context.yLabels = yLabels;

// Gera posições das linhas de grade (em porcentagem)
const gridLines = [];
for (let i = 1; i < ySteps; i++) {
  gridLines.push(Math.round((i / ySteps) * 100));
}
context.gridLines = gridLines;

// Helper: calcula altura da barra em porcentagem
context.handlebars.registerHelper('barPct', (value) => {
  if (value === null || value === undefined || value === 0) return 2;
  const pct = (value / maxScale) * 100;
  return Math.max(pct, 2).toFixed(1);
});

// Helper: decide se mostra label do eixo X
// Mostra: primeiro, último, e a cada N intervalos
context.handlebars.registerHelper('xLabel', (index, label) => {
  const total = dataLength;
  if (total <= 10) return label; // poucos dados, mostra todos

  const interval = Math.ceil(total / 7); // ~7 labels visíveis
  const isFirst = index === 0;
  const isLast = index === total - 1;
  const isInterval = index % interval === 0;

  return (isFirst || isLast || isInterval) ? label : '';
});

options.afterRender:
// Acknowledge button handler
context.element.querySelectorAll('.alarms__ack-btn').forEach(function(btn) {
  if (btn.dataset.listenerAdded) return;
  btn.dataset.listenerAdded = 'true';

  btn.addEventListener('click', function(e) {
    e.stopPropagation();
    var alarmId = btn.dataset.alarmId;

    if (!confirm('Acknowledge this alarm?')) return;

    var userName = (window.grafanaBootData && window.grafanaBootData.user) ? window.grafanaBootData.user.name : 'Unknown';
    var apiEndpoint = context.grafana.replaceVariables('${api_endpoint}');

    fetch(apiEndpoint + '/events-alarms/' + alarmId + '/acknowledge', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ acknowledged_by: userName })
    })
    .then(function(r) {
      if (r.ok) { location.reload(); }
      else { alert('Failed to acknowledge. Status: ' + r.status); }
    })
    .catch(function(err) { alert('Error: ' + err.message); });
  });
});

