// ============================================
// ALARMS TABLE - Helpers Configuration
// ============================================

// Helper: returns CSS class based on severity
context.handlebars.registerHelper('severityClass', (severity) => {
  if (!severity) return 'low';
  const s = severity.toString().toLowerCase();
  if (s === 'high') return 'high';
  if (s === 'medium') return 'medium';
  return 'low';
});

// Helper: calculates time ago from timestamp
context.handlebars.registerHelper('timeAgo', (timestamp) => {
  if (!timestamp) return '';
  try {
    const now = new Date();
    const then = new Date(timestamp);
    const diffMs = now - then;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'just now';
    if (diffMins < 60) return diffMins + 'min ago';
    if (diffHours < 24) return diffHours + 'h ago';
    if (diffDays < 7) return diffDays + 'd ago';
    return Math.floor(diffDays / 7) + 'w ago';
  } catch (e) {
    return '';
  }
});

// Helper: checks if alarm is new (< 1 hour)
context.handlebars.registerHelper('isNew', (timestamp) => {
  if (!timestamp) return false;
  try {
    const now = new Date();
    const then = new Date(timestamp);
    const diffMs = now - then;
    return diffMs < 3600000; // 1 hour in ms
  } catch (e) {
    return false;
  }
});

options.afterRender:
const API_KEY = '35430ed0e569a39bcd737092723631bc';

setTimeout(() => {
  const mapEl = document.getElementById('leaflet');
  
  if (!mapEl) {
    console.error('Leaflet element not found');
    return;
  }
  
  // Parse plant data
  let plants = [];
  try {
    const plantsData = mapEl.getAttribute('data-plants');
    plants = JSON.parse(plantsData);
    if (!Array.isArray(plants)) plants = [];
  } catch (e) {
    console.error('Error parsing plant data:', e);
    mapEl.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#999;font-size:14px;">⚠️ Error loading data</div>';
    return;
  }
  
  // Filter plants with valid coordinates
  plants = plants.filter(p => {
    const lat = parseFloat(p.latitude);
    const lon = parseFloat(p.longitude);
    return !isNaN(lat) && !isNaN(lon);
  });
  
  if (plants.length === 0) {
    mapEl.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#999;font-size:14px;">⚠️ No plants with available coordinates</div>';
    return;
  }
  
  console.log('Plants loaded:', plants);
  
  // **NOVA FUNÇÃO: Agrupar usinas por coordenadas**
  function groupPlantsByLocation(plants) {
    const groups = {};
    
    plants.forEach(plant => {
      // Criar chave única baseada nas coordenadas
      const key = `${parseFloat(plant.latitude).toFixed(6)}_${parseFloat(plant.longitude).toFixed(6)}`;
      
      if (!groups[key]) {
        groups[key] = {
          lat: parseFloat(plant.latitude),
          lon: parseFloat(plant.longitude),
          plants: []
        };
      }
      groups[key].plants.push(plant);
    });
    
    return Object.values(groups);
  }
  
  // Function to get visual configuration based on status
  function getStatusConfig(status) {
    const configs = {
      'critical': { color: '#DC2626', icon: '⚠️', label: 'Critical' },
      'acknowledged': { color: '#F97316', icon: '✓', label: 'Acknowledged' },
      'generating': { color: '#10B981', icon: '☀️', label: 'Generating' },
      'no_communication': { color: '#6B7280', icon: '✕', label: 'No Communication' },
      'unknown': { color: '#9CA3AF', icon: '?', label: 'Unknown' }
    };
    return configs[status] || configs['unknown'];
  }
  
  // **NOVA FUNÇÃO: Determinar status do grupo (pior status prevalece)**
  function getGroupStatus(plants) {
    const statusPriority = ['critical', 'acknowledged', 'no_communication', 'generating', 'unknown'];
    
    for (let status of statusPriority) {
      if (plants.some(p => p.status === status)) {
        return status;
      }
    }
    return 'unknown';
  }
  
  import("https://esm.sh/leaflet@1.9.4").then(({ default: L }) => {
    
    // Salvar estado do mapa se já existe
    let savedCenter = null;
    let savedZoom = null;
    let isFirstLoad = true;
    
    if (window.leafletMap) {
      savedCenter = window.leafletMap.getCenter();
      savedZoom = window.leafletMap.getZoom();
      isFirstLoad = false;
      window.leafletMap.remove();
    }
    
    // Calculate center and bounds for all plants
    const bounds = L.latLngBounds(plants.map(p => [parseFloat(p.latitude), parseFloat(p.longitude)]));
    
    const map = L.map('leaflet', {
      zoomControl: true
    });
    
    window.leafletMap = map;
    
    // Satellite
    L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
      attribution: 'Esri',
      maxZoom: 18
    }).addTo(map);
    
    // Clouds
    let clouds = L.tileLayer('https://tile.openweathermap.org/map/clouds_new/{z}/{x}/{y}.png?appid=' + API_KEY, {
      opacity: 0.85,
      maxZoom: 18
    }).addTo(map);
    
    let cloudsVisible = true;
    
    // Cloud button control
    const toggleBtn = document.getElementById('cloudToggle');
    if (toggleBtn) {
      toggleBtn.addEventListener('click', () => {
        if (cloudsVisible) {
          map.removeLayer(clouds);
          toggleBtn.classList.remove('active');
          toggleBtn.textContent = '☁️ Clouds (OFF)';
        } else {
          clouds.addTo(map);
          toggleBtn.classList.add('active');
          toggleBtn.textContent = '☁️ Clouds';
        }
        cloudsVisible = !cloudsVisible;
      });
    }
    
    // **AGRUPAR USINAS POR LOCALIZAÇÃO**
    const plantGroups = groupPlantsByLocation(plants);
    
    console.log('Plant groups:', plantGroups);
    
    // **CRIAR MARCADOR PARA CADA GRUPO**
    plantGroups.forEach((group) => {
      const lat = group.lat;
      const lon = group.lon;
      const plantsInGroup = group.plants;
      const isMultiple = plantsInGroup.length > 1;
      
      // Determinar status do grupo
      const groupStatus = getGroupStatus(plantsInGroup);
      const statusConfig = getStatusConfig(groupStatus);
      
      // **ÍCONE DIFERENTE PARA GRUPOS MÚLTIPLOS**
      let iconHtml;
      if (isMultiple) {
        iconHtml = '<div style="background:' + statusConfig.color + ';width:42px;height:42px;border-radius:50%;border:3px solid #fff;box-shadow:0 3px 10px rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;font-size:16px;font-weight:bold;color:white;">' + plantsInGroup.length + '</div>';
      } else {
        iconHtml = '<div style="background:' + statusConfig.color + ';width:36px;height:36px;border-radius:50%;border:3px solid #fff;box-shadow:0 3px 10px rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;font-size:20px;">' + statusConfig.icon + '</div>';
      }
      
      const icon = L.divIcon({
        className: '',
        html: iconHtml,
        iconSize: isMultiple ? [42, 42] : [36, 36],
        iconAnchor: isMultiple ? [21, 21] : [18, 18]
      });
      
      // **CRIAR POPUP BASEADO NO NÚMERO DE USINAS**
      let popupContent;
      
      if (isMultiple) {
        // Popup para múltiplas usinas
        popupContent = '<div style="max-width:300px;max-height:400px;overflow-y:auto;">';
        popupContent += '<div style="font-weight:bold;margin-bottom:8px;padding:8px;background:#f5f5f5;border-radius:4px;">📍 ' + plantsInGroup.length + ' usinas neste local</div>';
        
        plantsInGroup.forEach((plant) => {
          const name = plant.power_plant_name;
          const capacity = plant.capacity;
          const status = plant.status || 'unknown';
          const activePower = parseFloat(plant.active_power_kw) || 0;
          const highAlarmsCount = parseInt(plant.high_alarms_count) || 0;
          const config = getStatusConfig(status);
          
          popupContent += '<div style="padding:8px;border-bottom:1px solid #ddd;cursor:pointer;" onclick="window.location.href=\'https://nexus-gridco.com.br/d/ad4v9dd/powerplant-view?orgId=1&from=now%2Fd&to=now&timezone=browser&var-power_plant_id=' + plant.id + '&refresh=30s\'">';
          popupContent += '<b style="font-size:13px;">' + name + '</b>';
          popupContent += '<span style="display:inline-block;margin-left:5px;padding:2px 6px;background:' + config.color + ';color:white;border-radius:3px;font-size:10px;font-weight:bold;">' + config.label + '</span><br>';
          popupContent += '<span style="font-size:11px;color:#666;">🏭 ' + capacity + ' kWp | ⚡ ' + activePower.toFixed(2) + ' kW';
          
          if (highAlarmsCount > 0) {
            popupContent += ' | <span style="color:#DC2626;">🚨 ' + highAlarmsCount + ' alarmes</span>';
          }
          
          popupContent += '</span></div>';
        });
        
        popupContent += '</div>';
        
      } else {
        // Popup para usina única (código original)
        const plant = plantsInGroup[0];
        const name = plant.power_plant_name;
        const location = plant.location;
        const capacity = plant.capacity;
        const status = plant.status || 'unknown';
        const activePower = parseFloat(plant.active_power_kw) || 0;
        const highAlarmsCount = parseInt(plant.high_alarms_count) || 0;
        
        popupContent = '<div style="min-width:200px;">' +
          '<b style="font-size:14px;">' + name + '</b><br>' +
          '<span style="color:#666;font-size:12px;">' + location + '</span><br>' +
          '<span style="font-size:12px;"><b>Capacity:</b> ' + capacity + ' kWp</span><br>' +
          '<span style="font-size:12px;"><b>Active Power:</b> ' + activePower.toFixed(2) + ' kW</span><br>';
        
        if (highAlarmsCount > 0) {
          popupContent += '<span style="font-size:12px;color:#DC2626;"><b>⚠️ HIGH Alarms:</b> ' + highAlarmsCount + '</span><br>';
        }
        
        popupContent += '<span style="display:inline-block;margin-top:4px;padding:2px 8px;background:' + statusConfig.color + ';color:white;border-radius:4px;font-size:11px;font-weight:bold;">' + statusConfig.label + '</span>' +
          '</div>';
      }
      
      const marker = L.marker([lat, lon], {icon: icon})
        .addTo(map)
        .bindPopup(popupContent);
      
      // Abrir popup no hover
      marker.on('mouseover', function() {
        this.openPopup();
      });
      
      // Fechar popup quando sair do hover
      marker.on('mouseout', function() {
        this.closePopup();
      });
      
      // **COMPORTAMENTO DO CLICK**
      if (isMultiple) {
        // Para múltiplas usinas, o popup já tem os links clicáveis
        marker.on('click', function() {
          this.openPopup();
        });
      } else {
        // Para usina única, redirecionar direto
        marker.on('click', function() {
          const plant = plantsInGroup[0];
          const url = 'https://nexus-gridco.com.br/d/ad4v9dd/powerplant-view?orgId=1&from=now%2Fd&to=now&timezone=browser&var-power_plant_id=' + plant.id + '&refresh=30s';
          window.location.href = url;
        });
      }
      
      // Se for apenas um grupo com uma usina, abrir o popup
      if (plantGroups.length === 1 && !isMultiple) {
        marker.openPopup();
      }
    });
    
    // Ajustar zoom para mostrar todas as usinas (apenas no primeiro carregamento)
    if (isFirstLoad) {
      if (plants.length === 1) {
        map.setView([parseFloat(plants[0].latitude), parseFloat(plants[0].longitude)], 16);
      } else {
        map.fitBounds(bounds, { padding: [50, 50] });
      }
    } else if (savedCenter && savedZoom) {
      // Restaurar zoom e centro salvos nos refreshes
      map.setView(savedCenter, savedZoom);
    }
    
    setTimeout(() => map.invalidateSize(), 200);
    
    function updateTime() {
      const el = document.getElementById('time');
      if (el) {
        el.textContent = 'Update: ' + new Date().toLocaleString('pt-BR', {
          day:'2-digit',
          month:'2-digit',
          hour:'2-digit',
          minute:'2-digit'
        });
      }
    }
    updateTime();
    
    // Atualizar nuvens a cada 30 min
    setInterval(() => {
      if (cloudsVisible) {
        try {
          map.removeLayer(clouds);
          clouds = L.tileLayer('https://tile.openweathermap.org/map/clouds_new/{z}/{x}/{y}.png?appid=' + API_KEY + '&_=' + Date.now(), {
            opacity: 0.85,
            maxZoom: 18
          }).addTo(map);
          updateTime();
        } catch(e) {
          console.error('Error updating clouds:', e);
        }
      }
    }, 1800000);
    
  }).catch(error => {
    console.error('Error loading Leaflet:', error);
    mapEl.innerHTML = '<div style="padding:20px;color:red;text-align:center;">Error loading map: ' + error.message + '</div>';
  });
  
}, 100);
